using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    // ── AddItem ────────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _sut.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(1, _sut.Items.Count);
        Assert.AreEqual(2, _sut.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _sut.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantityAndUsesLatestPrice()
    {
        _sut.AddItem("SKU-1", 2, 5.00m);
        _sut.AddItem("SKU-1", 3, 6.00m);

        Assert.AreEqual(1, _sut.Items.Count);
        Assert.AreEqual(5, _sut.Items["SKU-1"].Quantity);
        Assert.AreEqual(6.00m, _sut.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_MultipleSkus_AllAppearInCart()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.AddItem("B", 2, 20m);

        Assert.AreEqual(2, _sut.Items.Count);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.AddItem(sku!, 1, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_Throws(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", qty, 10m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _sut.AddItem("SKU-1", 1, -1m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _sut.AddItem("FREE", 1, 0m);

        Assert.AreEqual(0m, _sut.Items["FREE"].Price);
    }

    // ── RemoveItem ─────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-1", 1, 10m);
        _sut.RemoveItem("SKU-1");

        Assert.AreEqual(0, _sut.Items.Count);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void RemoveItem_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.RemoveItem(sku!));
    }

    // ── CalculateTotal ─────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _sut.AddItem("SKU-1", 3, 10.00m);

        Assert.AreEqual(30.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsAllItems()
    {
        _sut.AddItem("A", 2, 5.00m);   // 10
        _sut.AddItem("B", 1, 15.00m);  // 15

        Assert.AreEqual(25.00m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_ExcludesRemovedItem()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.AddItem("B", 1, 20m);
        _sut.RemoveItem("A");

        Assert.AreEqual(20m, _sut.CalculateTotal());
    }

    // ── ApplyCoupon ────────────────────────────────────────────

    [TestMethod]
    [DataRow("SAVE10", 10.00)]
    [DataRow("SAVE20", 20.00)]
    [DataRow("HALF",   50.00)]
    public void ApplyCoupon_ValidCode_SetsDiscount(string code, double expectedPercent)
    {
        _sut.ApplyCoupon(code);

        Assert.AreEqual((decimal)expectedPercent, _sut.DiscountPercent);
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_Works()
    {
        _sut.ApplyCoupon("save10");

        Assert.AreEqual(10m, _sut.DiscountPercent);
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ApplyCoupon_NullOrEmptyCode_Throws(string? code)
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon(code!));
    }

    // ── Coupon + Total integration ─────────────────────────────

    [TestMethod]
    [DataRow("SAVE10", 90.00)]
    [DataRow("SAVE20", 80.00)]
    [DataRow("HALF",   50.00)]
    public void CalculateTotal_WithCoupon_AppliesDiscount(string code, double expected)
    {
        _sut.AddItem("A", 2, 50.00m); // subtotal = 100
        _sut.ApplyCoupon(code);

        Assert.AreEqual((decimal)expected, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_CouponOnEmptyCart_ReturnsZero()
    {
        _sut.ApplyCoupon("HALF");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_ReplacesExistingCoupon()
    {
        _sut.AddItem("A", 1, 100m);
        _sut.ApplyCoupon("SAVE10");
        _sut.ApplyCoupon("SAVE20");

        Assert.AreEqual(80m, _sut.CalculateTotal());
    }
}

